"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[4750],{38014(n,t,r){r.r(t),r.d(t,{assets:()=>s,contentTitle:()=>u,default:()=>i,frontMatter:()=>d,metadata:()=>e,toc:()=>l});const e=JSON.parse('{"id":"cpp11/mutex-and-locks","title":"\u4e92\u65a5\u9501\u4e0e\u9501 (mutex\u3001lock_guard\u3001unique_lock)","description":"C++11 \u4e92\u65a5\u9501\u4e0e\u9501 (mutex\u3001lock_guard\u3001unique_lock) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp11/71-mutex-and-locks.md","sourceDirName":"cpp11","slug":"/cpp11/71-mutex-and-locks","permalink":"/LearnModernCpp/docs/cpp11/71-mutex-and-locks","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp11","permalink":"/LearnModernCpp/docs/tags/cpp-11"},{"inline":true,"label":"mutex_and_locks","permalink":"/LearnModernCpp/docs/tags/mutex-and-locks"}],"version":"current","sidebarPosition":72,"frontMatter":{"sidebar_position":72,"slug":"71-mutex-and-locks","title":"\u4e92\u65a5\u9501\u4e0e\u9501 (mutex\u3001lock_guard\u3001unique_lock)","description":"C++11 \u4e92\u65a5\u9501\u4e0e\u9501 (mutex\u3001lock_guard\u3001unique_lock) \u6559\u5b66\u793a\u4f8b","tags":["cpp11","mutex_and_locks"]},"sidebar":"docs","previous":{"title":"std::thread \u7ebf\u7a0b","permalink":"/LearnModernCpp/docs/cpp11/70-thread"},"next":{"title":"\u6761\u4ef6\u53d8\u91cf (condition_variable)","permalink":"/LearnModernCpp/docs/cpp11/72-condition-variable"}}');var o=r(74848),c=r(28453);const d={sidebar_position:72,slug:"71-mutex-and-locks",title:"\u4e92\u65a5\u9501\u4e0e\u9501 (mutex\u3001lock_guard\u3001unique_lock)",description:"C++11 \u4e92\u65a5\u9501\u4e0e\u9501 (mutex\u3001lock_guard\u3001unique_lock) \u6559\u5b66\u793a\u4f8b",tags:["cpp11","mutex_and_locks"]},u="\u4e92\u65a5\u9501\u4e0e\u9501 (mutex\u3001lock_guard\u3001unique_lock)",s={},l=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function a(n){const t={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,c.R)(),...n.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.header,{children:(0,o.jsx)(t.h1,{id:"\u4e92\u65a5\u9501\u4e0e\u9501-mutexlock_guardunique_lock",children:"\u4e92\u65a5\u9501\u4e0e\u9501 (mutex\u3001lock_guard\u3001unique_lock)"})}),"\n",(0,o.jsx)(t.p,{children:"C++11 \u6807\u51c6\u5f15\u5165\u7684 \u4e92\u65a5\u9501\u4e0e\u9501 (mutex\u3001lock_guard\u3001unique_lock) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,o.jsx)(t.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,o.jsx)(t.pre,{children:(0,o.jsx)(t.code,{className:"language-cpp",metastring:'title="cpp11/71_mutex_and_locks.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u4e92\u65a5\u9501\u4e0e\u9501 (mutex\u3001lock_guard\u3001unique_lock)\r\n * \u6240\u5c5e\u6807\u51c6: C++11\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: C++11\u63d0\u4f9b\u4e86 std::mutex \u4e92\u65a5\u9501\u53ca\u5176RAII\u5c01\u88c5 lock_guard \u548c\r\n *           unique_lock\uff0c\u7528\u4e8e\u4fdd\u62a4\u5171\u4eab\u6570\u636e\u907f\u514d\u6570\u636e\u7ade\u4e89\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u591a\u7ebf\u7a0b\u5e76\u53d1\u8bbf\u95ee\u5171\u4eab\u6570\u636e\u65f6\uff0c\u5982\u679c\u4e0d\u52a0\u540c\u6b65\uff0c\u4f1a\u5bfc\u81f4\u6570\u636e\u7ade\u4e89\r\n *               \uff08Data Race\uff09\uff0c\u4ea7\u751f\u672a\u5b9a\u4e49\u884c\u4e3a\u3002\u4e92\u65a5\u9501\u63d0\u4f9b\u4e86\u4e92\u65a5\u8bbf\u95ee\u7684\u673a\u5236\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - std::mutex: \u57fa\u672c\u4e92\u65a5\u9501\uff0c\u63d0\u4f9b lock/unlock/try_lock\r\n *   - std::lock_guard: RAII\u98ce\u683c\u9501\uff0c\u6784\u9020\u65f6\u52a0\u9501\uff0c\u6790\u6784\u65f6\u89e3\u9501\uff0c\u4e0d\u53ef\u8f6c\u79fb\r\n *   - std::unique_lock: \u66f4\u7075\u6d3b\u7684RAII\u9501\uff0c\u652f\u6301\u5ef6\u8fdf\u9501\u5b9a\u3001\u624b\u52a8\u89e3\u9501\u3001\u8f6c\u79fb\u6240\u6709\u6743\r\n *   - std::lock(): \u540c\u65f6\u9501\u5b9a\u591a\u4e2a\u4e92\u65a5\u91cf\uff0c\u907f\u514d\u6b7b\u9501\r\n *   - std::recursive_mutex: \u5141\u8bb8\u540c\u4e00\u7ebf\u7a0b\u591a\u6b21\u9501\u5b9a\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <thread>\r\n#include <mutex>\r\n#include <vector>\r\n#include <string>\r\n#include <chrono>\r\n#include <algorithm>\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // 1. \u6570\u636e\u7ade\u4e89\u95ee\u9898\u6f14\u793a\r\n    std::cout << "[1] \u65e0\u9501\u4fdd\u62a4\u7684\u6570\u636e\u7ade\u4e89:\\n";\r\n    {\r\n        int counter = 0;\r\n        const int ITERATIONS = 100000;\r\n\r\n        auto increment = [&counter]() {\r\n            for (int i = 0; i < ITERATIONS; ++i) {\r\n                ++counter;  // \u6570\u636e\u7ade\u4e89\uff01\r\n            }\r\n        };\r\n\r\n        std::thread t1(increment);\r\n        std::thread t2(increment);\r\n        t1.join();\r\n        t2.join();\r\n\r\n        std::cout << "  \u65e0\u9501 counter (\u671f\u671b " << ITERATIONS * 2 << "): "\r\n                  << counter << std::endl;\r\n        std::cout << "  (\u7531\u4e8e\u6570\u636e\u7ade\u4e89\uff0c\u7ed3\u679c\u53ef\u80fd\u4e0d\u6b63\u786e)\\n";\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 2. mutex \u89e3\u51b3\u6570\u636e\u7ade\u4e89\r\n    std::cout << "[2] \u7528 mutex \u4fdd\u62a4\u5171\u4eab\u6570\u636e:\\n";\r\n    {\r\n        int counter = 0;\r\n        std::mutex mtx;\r\n        const int ITERATIONS = 100000;\r\n\r\n        auto increment = [&]() {\r\n            for (int i = 0; i < ITERATIONS; ++i) {\r\n                mtx.lock();\r\n                ++counter;\r\n                mtx.unlock();\r\n            }\r\n        };\r\n\r\n        std::thread t1(increment);\r\n        std::thread t2(increment);\r\n        t1.join();\r\n        t2.join();\r\n\r\n        std::cout << "  \u6709\u9501 counter (\u671f\u671b " << ITERATIONS * 2 << "): "\r\n                  << counter << std::endl;\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 3. lock_guard: RAII \u81ea\u52a8\u7ba1\u7406\u9501\r\n    std::cout << "[3] lock_guard (RAII\u81ea\u52a8\u7ba1\u7406):\\n";\r\n    {\r\n        int counter = 0;\r\n        std::mutex mtx;\r\n        const int ITERATIONS = 100000;\r\n\r\n        auto increment = [&]() {\r\n            for (int i = 0; i < ITERATIONS; ++i) {\r\n                std::lock_guard<std::mutex> lock(mtx);  // \u6784\u9020\u65f6\u52a0\u9501\r\n                ++counter;\r\n            } // \u6790\u6784\u65f6\u81ea\u52a8\u89e3\u9501\r\n        };\r\n\r\n        std::thread t1(increment);\r\n        std::thread t2(increment);\r\n        t1.join();\r\n        t2.join();\r\n\r\n        std::cout << "  lock_guard counter (\u671f\u671b " << ITERATIONS * 2 << "): "\r\n                  << counter << std::endl;\r\n        std::cout << "  lock_guard \u597d\u5904: \u5f02\u5e38\u5b89\u5168\uff0c\u4e0d\u4f1a\u5fd8\u8bb0\u89e3\u9501\\n";\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 4. unique_lock: \u66f4\u7075\u6d3b\u7684\u9501\r\n    std::cout << "[4] unique_lock (\u7075\u6d3b\u9501\u5b9a/\u89e3\u9501):\\n";\r\n    {\r\n        std::mutex mtx;\r\n        int shared_data = 0;\r\n\r\n        auto worker = [&](int id) {\r\n            // unique_lock \u5141\u8bb8\u624b\u52a8\u63a7\u5236\r\n            std::unique_lock<std::mutex> lock(mtx);\r\n            shared_data += id;\r\n            std::cout << "  \u7ebf\u7a0b" << id << " \u6301\u9501\u4fee\u6539: " << shared_data << std::endl;\r\n\r\n            lock.unlock();  // \u53ef\u4ee5\u63d0\u524d\u89e3\u9501\r\n            // \u6267\u884c\u4e0d\u9700\u8981\u9501\u7684\u64cd\u4f5c...\r\n            std::this_thread::sleep_for(std::chrono::milliseconds(10));\r\n\r\n            lock.lock();    // \u53ef\u4ee5\u91cd\u65b0\u52a0\u9501\r\n            shared_data += id * 10;\r\n            std::cout << "  \u7ebf\u7a0b" << id << " \u91cd\u65b0\u52a0\u9501\u4fee\u6539: " << shared_data << std::endl;\r\n        }; // \u6790\u6784\u65f6\u81ea\u52a8\u89e3\u9501\uff08\u5982\u679c\u8fd8\u6301\u6709\u9501\uff09\r\n\r\n        std::thread t1(worker, 1);\r\n        std::thread t2(worker, 2);\r\n        t1.join();\r\n        t2.join();\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 5. try_lock \u975e\u963b\u585e\u5c1d\u8bd5\r\n    std::cout << "[5] try_lock (\u975e\u963b\u585e\u5c1d\u8bd5):\\n";\r\n    {\r\n        std::mutex mtx;\r\n\r\n        auto worker = [&](int id) {\r\n            for (int i = 0; i < 5; ++i) {\r\n                if (mtx.try_lock()) {\r\n                    std::cout << "  \u7ebf\u7a0b" << id << " \u83b7\u5f97\u9501 (\u7b2c" << i << "\u6b21)\\n";\r\n                    std::this_thread::sleep_for(std::chrono::milliseconds(10));\r\n                    mtx.unlock();\r\n                } else {\r\n                    std::cout << "  \u7ebf\u7a0b" << id << " \u672a\u83b7\u5f97\u9501\uff0c\u8df3\u8fc7 (\u7b2c" << i << "\u6b21)\\n";\r\n                }\r\n            }\r\n        };\r\n\r\n        std::thread t1(worker, 1);\r\n        std::thread t2(worker, 2);\r\n        t1.join();\r\n        t2.join();\r\n    }\r\n    std::cout << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u9ad8\u7ea7\u7528\u6cd5\r\n// ============================================================\r\nvoid advanced_usage() {\r\n    std::cout << "--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // 1. std::lock \u907f\u514d\u6b7b\u9501\r\n    std::cout << "[1] std::lock \u907f\u514d\u6b7b\u9501:\\n";\r\n    {\r\n        struct Account {\r\n            std::string name;\r\n            int balance;\r\n            std::mutex mtx;\r\n            Account(const std::string& n, int b) : name(n), balance(b) {}\r\n        };\r\n\r\n        Account alice("Alice", 1000);\r\n        Account bob("Bob", 500);\r\n\r\n        auto transfer = [](Account& from, Account& to, int amount) {\r\n            // std::lock \u540c\u65f6\u9501\u5b9a\u4e24\u4e2a\u4e92\u65a5\u91cf\uff0c\u907f\u514d\u6b7b\u9501\r\n            std::lock(from.mtx, to.mtx);\r\n\r\n            // adopt_lock: \u544a\u8bc9 lock_guard \u4e92\u65a5\u91cf\u5df2\u7ecf\u9501\u5b9a\uff0c\u53ea\u9700\u63a5\u7ba1\r\n            std::lock_guard<std::mutex> lock1(from.mtx, std::adopt_lock);\r\n            std::lock_guard<std::mutex> lock2(to.mtx, std::adopt_lock);\r\n\r\n            if (from.balance >= amount) {\r\n                from.balance -= amount;\r\n                to.balance += amount;\r\n                std::cout << "  \u8f6c\u8d26 " << amount << ": "\r\n                          << from.name << "(" << from.balance << ") -> "\r\n                          << to.name << "(" << to.balance << ")" << std::endl;\r\n            }\r\n        };\r\n\r\n        // \u4e24\u4e2a\u7ebf\u7a0b\u540c\u65f6\u8f6c\u8d26\uff08\u65b9\u5411\u76f8\u53cd\uff09\uff0c\u4f7f\u7528 std::lock \u4e0d\u4f1a\u6b7b\u9501\r\n        std::thread t1(transfer, std::ref(alice), std::ref(bob), 100);\r\n        std::thread t2(transfer, std::ref(bob), std::ref(alice), 50);\r\n        t1.join();\r\n        t2.join();\r\n\r\n        std::cout << "  \u6700\u7ec8: " << alice.name << "=" << alice.balance\r\n                  << ", " << bob.name << "=" << bob.balance << std::endl;\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 2. unique_lock \u4e0e defer_lock\r\n    std::cout << "[2] unique_lock \u4e0e defer_lock:\\n";\r\n    {\r\n        std::mutex mtx1, mtx2;\r\n\r\n        auto worker = [&]() {\r\n            // defer_lock: \u53ea\u521b\u5efa lock \u5bf9\u8c61\uff0c\u4e0d\u7acb\u5373\u52a0\u9501\r\n            std::unique_lock<std::mutex> lock1(mtx1, std::defer_lock);\r\n            std::unique_lock<std::mutex> lock2(mtx2, std::defer_lock);\r\n\r\n            // \u4f7f\u7528 std::lock \u540c\u65f6\u52a0\u9501\r\n            std::lock(lock1, lock2);\r\n\r\n            std::cout << "  \u540c\u65f6\u6301\u6709\u4e24\u4e2a\u9501" << std::endl;\r\n        }; // \u6790\u6784\u65f6\u81ea\u52a8\u89e3\u9501\r\n\r\n        std::thread t(worker);\r\n        t.join();\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 3. recursive_mutex\r\n    std::cout << "[3] recursive_mutex (\u9012\u5f52\u4e92\u65a5\u91cf):\\n";\r\n    {\r\n        std::recursive_mutex rmtx;\r\n        int value = 0;\r\n\r\n        // \u666e\u901a mutex \u540c\u4e00\u7ebf\u7a0b\u91cd\u590d lock \u4f1a\u6b7b\u9501\r\n        // recursive_mutex \u5141\u8bb8\u540c\u4e00\u7ebf\u7a0b\u591a\u6b21\u52a0\u9501\r\n        auto recursive_fn = [&](int depth) {\r\n            std::lock_guard<std::recursive_mutex> lock(rmtx);\r\n            value += depth;\r\n            if (depth > 0) {\r\n                // \u9012\u5f52\u8c03\u7528\uff0c\u518d\u6b21\u52a0\u9501\uff08\u540c\u4e00\u7ebf\u7a0b\uff09\r\n                std::lock_guard<std::recursive_mutex> lock2(rmtx);\r\n                value += depth;\r\n            }\r\n        };\r\n\r\n        std::thread t(recursive_fn, 3);\r\n        t.join();\r\n        std::cout << "  recursive_mutex: value = " << value << std::endl;\r\n        std::cout << "  \u540c\u4e00\u7ebf\u7a0b\u53ef\u4ee5\u591a\u6b21\u9501\u5b9a recursive_mutex\\n";\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 4. \u7ebf\u7a0b\u5b89\u5168\u5bb9\u5668\u5305\u88c5\r\n    std::cout << "[4] \u7ebf\u7a0b\u5b89\u5168\u5bb9\u5668\u5305\u88c5:\\n";\r\n    {\r\n        class ThreadSafeVector {\r\n            std::vector<int> data_;\r\n            mutable std::mutex mtx_;\r\n\r\n        public:\r\n            void push_back(int val) {\r\n                std::lock_guard<std::mutex> lock(mtx_);\r\n                data_.push_back(val);\r\n            }\r\n\r\n            int size() const {\r\n                std::lock_guard<std::mutex> lock(mtx_);\r\n                return static_cast<int>(data_.size());\r\n            }\r\n\r\n            std::string to_string() const {\r\n                std::lock_guard<std::mutex> lock(mtx_);\r\n                std::string result;\r\n                for (int v : data_) {\r\n                    if (!result.empty()) result += " ";\r\n                    result += std::to_string(v);\r\n                }\r\n                return result;\r\n            }\r\n        };\r\n\r\n        ThreadSafeVector vec;\r\n\r\n        auto writer = [&vec](int start) {\r\n            for (int i = start; i < start + 5; ++i) {\r\n                vec.push_back(i);\r\n            }\r\n        };\r\n\r\n        std::thread t1(writer, 0);\r\n        std::thread t2(writer, 100);\r\n        t1.join();\r\n        t2.join();\r\n\r\n        std::cout << "  \u7ebf\u7a0b\u5b89\u5168vector\u5927\u5c0f: " << vec.size() << std::endl;\r\n        std::cout << "  \u5185\u5bb9: " << vec.to_string() << std::endl;\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 5. unique_lock \u7684\u6240\u6709\u6743\u8f6c\u79fb\r\n    std::cout << "[5] unique_lock \u7684\u6240\u6709\u6743\u8f6c\u79fb:\\n";\r\n    {\r\n        std::mutex mtx;\r\n\r\n        auto get_lock = [&mtx]() -> std::unique_lock<std::mutex> {\r\n            std::unique_lock<std::mutex> lock(mtx);\r\n            // \u51c6\u5907\u5171\u4eab\u6570\u636e...\r\n            return lock;  // \u79fb\u52a8\u8fd4\u56de\u9501\r\n        };\r\n\r\n        // \u63a5\u6536\u51fd\u6570\u8fd4\u56de\u7684\u9501\uff08\u6240\u6709\u6743\u8f6c\u79fb\uff09\r\n        std::unique_lock<std::mutex> my_lock = get_lock();\r\n        std::cout << "  \u9501\u7684\u6240\u6709\u6743\u5df2\u8f6c\u79fb\\n";\r\n        std::cout << "  owns_lock(): " << (my_lock.owns_lock() ? "\u662f" : "\u5426") << std::endl;\r\n    } // \u8fd9\u91cc\u81ea\u52a8\u89e3\u9501\r\n    std::cout << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9\r\n// ============================================================\r\nvoid pitfalls() {\r\n    std::cout << "--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // 1. \u5fd8\u8bb0\u89e3\u9501\r\n    std::cout << "[1] \u76f4\u63a5\u4f7f\u7528 mutex \u5bb9\u6613\u5fd8\u8bb0\u89e3\u9501:\\n";\r\n    std::cout << "  // mtx.lock();\\n";\r\n    std::cout << "  // // \u5982\u679c\u8fd9\u91cc\u629b\u51fa\u5f02\u5e38\uff0cmutex\u6c38\u8fdc\u4e0d\u4f1a\u89e3\u9501\uff01\\n";\r\n    std::cout << "  // do_something_that_might_throw();\\n";\r\n    std::cout << "  // mtx.unlock();\\n";\r\n    std::cout << "  \u89e3\u51b3: \u59cb\u7ec8\u4f7f\u7528 lock_guard \u6216 unique_lock\\n\\n";\r\n\r\n    // 2. \u6b7b\u9501\r\n    std::cout << "[2] \u6b7b\u9501\u7684\u5e38\u89c1\u539f\u56e0:\\n";\r\n    std::cout << "  - \u4e24\u4e2a\u7ebf\u7a0b\u4ee5\u4e0d\u540c\u987a\u5e8f\u9501\u5b9a\u4e24\u4e2a\u4e92\u65a5\u91cf\\n";\r\n    std::cout << "  - \u540c\u4e00\u7ebf\u7a0b\u5bf9\u975e\u9012\u5f52mutex\u91cd\u590d\u52a0\u9501\\n";\r\n    std::cout << "  \u907f\u514d\u65b9\u6cd5:\\n";\r\n    std::cout << "    1) \u59cb\u7ec8\u4ee5\u76f8\u540c\u987a\u5e8f\u52a0\u9501\\n";\r\n    std::cout << "    2) \u4f7f\u7528 std::lock() \u4e00\u6b21\u6027\u9501\u5b9a\u591a\u4e2a\\n";\r\n    std::cout << "    3) \u4f7f\u7528 recursive_mutex\uff08\u5982\u9700\u9012\u5f52\uff09\\n\\n";\r\n\r\n    // 3. \u9501\u7684\u7c92\u5ea6\r\n    std::cout << "[3] \u9501\u7684\u7c92\u5ea6\u8981\u9002\u5f53:\\n";\r\n    std::cout << "  - \u7c92\u5ea6\u592a\u7c97: \u6301\u9501\u65f6\u95f4\u957f\uff0c\u964d\u4f4e\u5e76\u53d1\u6027\\n";\r\n    std::cout << "  - \u7c92\u5ea6\u592a\u7ec6: \u9891\u7e41\u52a0\u9501\u89e3\u9501\uff0c\u589e\u52a0\u5f00\u9500\\n";\r\n    std::cout << "  - \u539f\u5219: \u53ea\u5728\u8bbf\u95ee\u5171\u4eab\u6570\u636e\u65f6\u6301\u6709\u9501\\n";\r\n    {\r\n        std::mutex mtx;\r\n        auto good_practice = [&mtx]() {\r\n            // \u4e0d\u9700\u8981\u9501\u7684\u8ba1\u7b97\r\n            int local_result = 42 * 100;\r\n\r\n            {\r\n                std::lock_guard<std::mutex> lock(mtx);\r\n                // \u53ea\u5728\u8fd9\u91cc\u8bbf\u95ee\u5171\u4eab\u6570\u636e\r\n                (void)local_result;  // \u5047\u88c5\u5199\u5165\u5171\u4eab\u6570\u636e\r\n            } // \u7acb\u5373\u89e3\u9501\r\n\r\n            // \u4e0d\u9700\u8981\u9501\u7684\u540e\u7eed\u5904\u7406\r\n        };\r\n        std::thread t(good_practice);\r\n        t.join();\r\n        std::cout << "  \u6b63\u786e: \u6700\u5c0f\u5316\u6301\u9501\u533a\u57df\\n";\r\n    }\r\n    std::cout << std::endl;\r\n\r\n    // 4. lock_guard \u4e0d\u80fd\u624b\u52a8\u89e3\u9501\r\n    std::cout << "[4] lock_guard vs unique_lock:\\n";\r\n    std::cout << "  lock_guard:\\n";\r\n    std::cout << "    + \u7b80\u5355\u3001\u8f7b\u91cf\\n";\r\n    std::cout << "    - \u4e0d\u80fd\u624b\u52a8 unlock/lock\\n";\r\n    std::cout << "    - \u4e0d\u80fd\u79fb\u52a8\\n";\r\n    std::cout << "  unique_lock:\\n";\r\n    std::cout << "    + \u53ef\u4ee5\u624b\u52a8 unlock/lock\\n";\r\n    std::cout << "    + \u652f\u6301 defer_lock\u3001try_to_lock\\n";\r\n    std::cout << "    + \u53ef\u4ee5\u79fb\u52a8\u6240\u6709\u6743\\n";\r\n    std::cout << "    + \u914d\u5408 condition_variable \u4f7f\u7528\\n";\r\n    std::cout << "    - \u7565\u6709\u989d\u5916\u5f00\u9500\\n\\n";\r\n\r\n    // 5. mutable \u4e0e const \u65b9\u6cd5\r\n    std::cout << "[5] const \u65b9\u6cd5\u4e2d\u9700\u8981 mutable mutex:\\n";\r\n    std::cout << "  // class Foo {\\n";\r\n    std::cout << "  //   mutable std::mutex mtx_;  // mutable!\\n";\r\n    std::cout << "  //   int data_;\\n";\r\n    std::cout << "  //   int getData() const {\\n";\r\n    std::cout << "  //     std::lock_guard<std::mutex> lock(mtx_);  // const\u4e2d\u4e5f\u80fd\u9501\\n";\r\n    std::cout << "  //     return data_;\\n";\r\n    std::cout << "  //   }\\n";\r\n    std::cout << "  // };\\n\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== \u4e92\u65a5\u9501\u4e0e\u9501 (mutex/lock_guard/unique_lock) - C++11 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,o.jsx)(t.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,o.jsxs)(t.ul,{children:["\n",(0,o.jsx)(t.li,{children:(0,o.jsx)(t.a,{href:"https://en.cppreference.com/w/cpp/thread/mutex",children:"cppreference: \u4e92\u65a5\u9501\u4e0e\u9501 (mutex\u3001lock_guard\u3001unique_lock)"})}),"\n"]})]})}function i(n={}){const{wrapper:t}={...(0,c.R)(),...n.components};return t?(0,o.jsx)(t,{...n,children:(0,o.jsx)(a,{...n})}):a(n)}},28453(n,t,r){r.d(t,{R:()=>d,x:()=>u});var e=r(96540);const o={},c=e.createContext(o);function d(n){const t=e.useContext(c);return e.useMemo(function(){return"function"==typeof n?n(t):{...t,...n}},[t,n])}function u(n){let t;return t=n.disableParentContext?"function"==typeof n.components?n.components(o):n.components||o:d(n.components),e.createElement(c.Provider,{value:t},n.children)}}}]);